import "../styles/Services.css";

export default function Services() {
  const services = [
    { name: "Web Design & Development", icon: "fas fa-laptop-code" },
    { name: "Mobile App Development", icon: "fas fa-mobile-alt" },
    { name: "Brand Identity & Logo Design", icon: "fas fa-palette" },
    { name: "UI/UX Prototyping", icon: "fas fa-keyboard" },
    { name: "Digital Marketing", icon: "fas fa-megaphone" },
    { name: "SEO Optimization", icon: "fas fa-search-dollar" },
    { name: "E-Commerce Solutions", icon: "fas fa-shopping-cart" },
    { name: "Social Media Strategy", icon: "fas fa-comments" },
    { name: "Cloud Integration", icon: "fas fa-cloud-upload-alt" },
    { name: "Consulting & Strategy", icon: "fas fa-briefcase" },
  ];

  return (
    <section className="services-section">
      <h3 className="section-title">Our Services</h3>
      <ul className="services-list">
        {services.map((service, index) => (
          <li key={index} className="service-item">
            <i className={`${service.icon} service-logo`} />
            <span>{service.name}</span>
          </li>
        ))}
      </ul>
    </section>
  );
}
